import { useState } from "react";
import { useTranslation } from "react-i18next";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { DISLIKE_REASONS } from "@/hooks/useStoryReactions";

interface DislikeReasonDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSubmit: (reason: string) => void;
}

const DislikeReasonDialog = ({ open, onOpenChange, onSubmit }: DislikeReasonDialogProps) => {
  const { i18n, t } = useTranslation();
  const [selected, setSelected] = useState<string | null>(null);

  const lang = i18n.language?.startsWith("zh") ? "zh" : i18n.language?.startsWith("pt") ? "pt" : "en";

  const handleSubmit = () => {
    if (selected) {
      onSubmit(selected);
      setSelected(null);
      onOpenChange(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={(v) => { if (!v) setSelected(null); onOpenChange(v); }}>
      <DialogContent className="max-w-sm">
        <DialogHeader>
          <DialogTitle>{t("story.dislikeReason", "请选择原因")}</DialogTitle>
          <DialogDescription>{t("story.dislikeReasonDesc", "您的反馈将帮助我们改进内容")}</DialogDescription>
        </DialogHeader>
        <div className="flex flex-col gap-2">
          {DISLIKE_REASONS.map((r) => (
            <button
              key={r.key}
              onClick={() => setSelected(r.key)}
              className={`text-left px-4 py-2.5 rounded-lg border text-sm transition-colors ${
                selected === r.key
                  ? "border-primary bg-primary/10 text-foreground font-medium"
                  : "border-border hover:border-primary/50 text-muted-foreground hover:text-foreground"
              }`}
            >
              {r[lang]}
            </button>
          ))}
        </div>
        <Button onClick={handleSubmit} disabled={!selected} className="mt-2">
          {t("common.confirm", "确认")}
        </Button>
      </DialogContent>
    </Dialog>
  );
};

export default DislikeReasonDialog;
